local RATE_LIMIT = ngx.shared.RateLimiter or ngx.shared.create("RateLimiter" , 1024, 10) -- 1024 keys, default expiration time is 10 seconds

function rate_limit(self, limit, burst)
    local ip = self.remote_addr
    local key = string.lower(ip)

    if not RATE_LIMIT:get(key) then
        RATE_LIMIT:set(key, 1, tonumber(burst))
    end

    local count = RATE_LIMIT:incr(key, -1) + 1
    if count > limit then
        ngx.exit(ngx.HTTP_TOO_MANY_REQUESTS)
    end
end

